interface CacheItem<T>{value:T;expiry:number|null;}class MemoryCache{private cache=new Map<string,CacheItem<any>>();set<T>(key:string,value:T,ttlMs?:number):void{const expiry=ttlMs?Date.now()+ttlMs:null;this.cache.set(key,{value,expiry});}get<T>(key:string):T|null{const item=this.cache.get(key);if(!item)return null;if(item.expiry&&Date.now()>item.expiry){this.cache.delete(key);return null;}return item.value;}has(key:string):boolean{return this.get(key)!==null;}delete(key:string):boolean{return this.cache.delete(key);}clear():void{this.cache.clear();}size():number{return this.cache.size;}}export const memoryCache=new MemoryCache();
